const { BREP } = api;

// Canopy — the disc on the ceiling.
const canopy = BREP.label(BREP.cone(15, 18, 4).translate([0, 0, 56]), 'canopy');

// Chain — extends to z=57 so it overlaps the canopy (z56..60) by 1mm.
const chain = BREP.label(BREP.cylinder(0.7, 31).translate([0, 0, 26]), 'chain');

// Central hub — solid cone, z24..32. The chain passes through it.
const hub = BREP.label(BREP.cone(4, 12, 8).translate([0, 0, 24]), 'hub');

// Arms — raised to z24.5..26 so each inner end (r=2) seats INSIDE the hub
// (hub r≈5 there) instead of floating 0.5mm below it. 5 around.
const armSeed = BREP.box([24, 1.5, 1.5]).translate([14, 0, 24.5]);
const arms = BREP.label(
  BREP.circularPattern(armSeed, 5, { radius: 0, axis: [0, 0, 1], angle: 360 }),
  'arm',
);

// Bulbs — sphere at each arm tip (x=26), centred at z=25 so it overlaps the arm.
const bulbSeed = BREP.sphere(3).translate([26, 0, 25]);
const bulbs = BREP.label(
  BREP.circularPattern(bulbSeed, 5, { radius: 0, axis: [0, 0, 1], angle: 360 }),
  'bulb',
);

// Finial — hangs below the hub; raised to z=23 so its top (z=25) pokes into
// the hub base (z=24) and fuses, while most of it stays visible below.
const finial = BREP.label(BREP.sphere(2).translate([0, 0, 23]), 'finial');

return BREP.fuseAll([canopy, chain, hub, arms, bulbs, finial]);

